import boto3
from botocore.exceptions import ClientError

sns = boto3.client('sns')

def publish_to_sns(event):
    try:
        message_content = event['message']
        topic_arn = event['topicArn']

        if 'type' in event and event['type'] == 'NEW_ITEM':
            sns.publish(
                TopicArn=topic_arn,
                Message=message_content
            )
        elif 'type' in event and event['type'] == 'UPDATE_ITEM':
            sns.publish(
                TopicArn=topic_arn,
                Message=message_content
            )
        else:
            sns.publish(
                TopicArn=topic_arn,
                Message=message_content
            )

    except ClientError as e:
        print(e)